Candle.go:
## Go

```go
candles, _ := api.GetCandles("EURUSD_otc", 60, 0)
for _, c := range candles {
    dir := "BULL"
    if c.Close < c.Open { dir = "BEAR" }
    fmt.Printf("[%d] %s %s O=%f C=%f\n", c.Timestamp, c.Symbol, dir, c.Open, c.Close)
}

// Live candles
stream, _ := api.Subscribe("EURUSD_otc", 5)
for i := 0; i < 20; i++ {
    c, err := stream.Next()
    if err != nil { break }
    fmt.Printf("Live: %s @ %f\n", c.Symbol, c.Close)
}
```

